begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(24047761944673939)
,p_install_id=>wwv_flow_imp.id(24047175510634017)
,p_name=>'10_ABM_MENU_ENTRIES'
,p_sequence=>10
,p_script_type=>'INSTALL'
,p_script_option=>'TABLE'
,p_condition_type=>'NOT_EXISTS'
,p_condition=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select 1',
'from tabs ',
'where table_name = ''ABM_MENU_ENTRIES'''))
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'CREATE TABLE "ABM_MENU_ENTRIES" ',
'   (	"ENTRY_ID" NUMBER(*,0) GENERATED BY DEFAULT AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 NOCACHE  ORDER  NOCYCLE  NOKEEP  NOT NULL ENABLE, ',
'	"ENTRY_TITLE" VARCHAR2(250 CHAR), ',
'	"SOURCE_APP_IDS" VARCHAR2(250 CHAR), ',
'	"ACTIVE_FOR" VARCHAR2(4000 CHAR), ',
'	"ACTIVE_FOR_TYPE" VARCHAR2(250 CHAR) DEFAULT ''TARGET'', ',
'	"TARGET_APP_ID" NUMBER(*,0), ',
'	"TARGET_PAGE_ID" NUMBER(*,0), ',
'	"TARGET_URL" VARCHAR2(4000 CHAR), ',
