prompt --application/deployment/install/install_30_create_package
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(24049685538722808)
,p_install_id=>wwv_flow_imp.id(24047175510634017)
,p_name=>'30_create_PACKAGE'
,p_sequence=>30
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'CREATE OR REPLACE EDITIONABLE PACKAGE "ABM_00000_MENU_PCK" is',
'   /*                                                                              888       d8888',
'                                                                                   888      d8P888',
'                                                                                   888     d8P 888',
'                                 __        .d8888b  88888b.d88b.   8888b.  888d888 888888 d8P  888',
'                            _.-~  )        88K      888 "888 "88b     "88b 888P"   888   d88   888',
'                 _..--~~~~,''   ,-/     _   "Y8888b. 888  888  888 .d888888 888     888   8888888888',
'              .-''. . . .''   ,-'',''    ,'' )       X88 888  888  888 888  888 888     Y88b.       888',
'            ,''. . . _   ,--~,-''__..-''  ,''   88888P'' 888  888  888 "Y888888 888      "Y888      888',
'          ,''. . .  (@)'' ---~~~~      ,''              888          888    d8b',
'         /. . . . ''~~             ,-''                888          888    Y8P',
'        /. . . . .             ,-''                   888          888',
'       ; . . . .  - .        ,''    .d8888b   .d88b.  888 888  888 888888 888  .d88b.  88888b.  .d8888b',
'      : . . . .       _     /      88K      d88""88b 888 888  888 888    888 d88""88b 888 "88b 88K',
'     . . . . .          `-.:       "Y8888b. 888  888 888 888  888 888    888 888  888 888  888 "Y8888b.',
'    . . . ./  - .          )            X88 Y88..88P 888 Y88b 888 Y88b.  888 Y88..88P 888  888      X88',
'   .  . . |  _____..---.._/         88888P''  "Y88P"  888  "Y88888  "Y888 888  "Y88P"  888  888  88888P''',
'   -~~----~~~~             ~---~~~~--~~~--~~~---~~~~~---~~~~----~~~~~---~~~--~~~---',
'   --    NAME',
'   --      abm_00000_menu_pck',
'   --',
'   --    DESCRIPTION',
'   --      menu related functions and procedures',
'   --',
'   --    MODIFIED   (MM/DD/YYYY)',
'   --    RMARTENS  3/24/2023 12:16:20 PM - Created',
'   --------------------------------------------------------------------------------',
'   */',
'   function subst_strings(in_string in varchar2) return varchar2;',
'   ',
'   function validate_condition(in_condition in varchar2) return varchar2;',
'',
'end abm_00000_menu_pck;',
'/',
'',
'',
'CREATE OR REPLACE EDITIONABLE PACKAGE BODY "ABM_00000_MENU_PCK" is',
'',
'  co_true  constant varchar2(10) := ''TRUE'';',
'  co_false constant varchar2(10) := ''FALSE'';',
'',
'   -- return the in_string where the &**. substitutions are replaced',
'   function subst_strings(in_string in varchar2) return varchar2',
'   is',
'     l_retval varchar2(32767) := in_string;',
'   begin',
'     <<subststrings>>',
'     for r_subst_string in (with iv_data',
'                            as (select level',
'                                      ,regexp_substr(in_string, ''\&\w*\.'', 1, level, ''i'') as expr',
'                                  from dual',
'                                connect by level < 100)',
'                            select d.expr',
'                                  ,v(replace(replace(upper(d.expr), ''&''), ''.'')) as result_value',
'                            from iv_data d',
'                            where expr is not null)',
'     loop',
'       l_retval := replace(l_retval, r_subst_string.expr, r_subst_string.result_value);',
'     end loop subsstrings;',
'     ',
'     return l_retval;',
'     ',
'   end subst_strings;',
'',
'   -- return ''TRUE'' or ''FALSe''',
'   function validate_condition(in_condition in varchar2) return varchar2 is',
'      l_result varchar2(1);',
'   begin',
'   ',
'      execute immediate ''select ''''1'''' from dual where '' || in_condition',
'         into l_result;',
'   ',
'      return case l_result',
'                when ''1'' ',
'                  then co_true',
'                else co_false',
'             end;',
'   ',
'   exception',
'      when no_data_found then',
'         return co_false;',
'      ',
'   end validate_condition;',
'',
'end abm_00000_menu_pck;',
'/',
'',
''))
);
