prompt --application/deployment/install/install_40_create_views
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(24048381613718323)
,p_install_id=>wwv_flow_imp.id(24047175510634017)
,p_name=>'40_create_VIEWS'
,p_sequence=>40
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "ABM_00000_MENU_ENTRIES_VW" ("ENTRY_ID", "ROW_NUMBER", "LABEL", "SOURCE_APP_IDS", "TARGET_APP_ID", "TARGET_PAGE_ID", "TARGET_URL", "TARGET_ITEMS", "TARGET_VALUES", "TARGET_REQUEST", "PARENT_ENTRY") AS ',
'  select muey.entry_id',
'      ,rownum as row_number',
'      ,muey.entry_title as "LABEL"',
'      ,muey.source_app_ids',
'      ,muey.target_app_id',
'      ,muey.target_page_id',
'      ,muey.target_url',
'      ,muey.target_items',
'      ,muey.target_values',
'      ,muey.target_request',
'      ,muey.parent_entry',
'from abm_menu_entries muey',
'connect by prior muey.entry_id = muey.parent_entry',
'  start with muey.parent_entry is null',
'  order siblings by muey.order_nr',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "ABM_00000_MENU_VW" ("ROW_NUMBER", "LEVEL", "LABEL", "CURR_APP_ID", "TARGET", "IS_CURRENT_LIST_ENTRY", "IMAGE", "IMAGE_ATTRIBUTE", "IMAGE_ALT_ATTRIBUTE", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4",'
||' "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10") AS ',
'  with iv_menu_entries',
'as (select level                                as niveau',
'          ,rownum                               as row_number',
'          ,acap.column_value                    as curr_app_id_colval',
'          ,nvl(v(''APP_ID''), ''100'')              as curr_app_id',
'          ,nvl(v(''APP_PAGE_ID''), ''10010'')       as curr_page_id',
'          ,connect_by_root m.entry_id           as cbr',
'          ,sys_connect_by_path(m.entry_id, ''/'') as cbp',
'          ,sys_connect_by_path(m.target_app_id || '':'' || m.target_page_id || '':'' || m.entry_id, ''/'') as cbt',
'          ,case',
'             when m.server_side_condition is null then ''TRUE''',
'             else abm_00000_menu_pck.validate_condition(in_condition => m.server_side_condition)',
'           end as ssc_result',
'          ,m.*',
'      from abm_menu_entries m',
'        join table(apex_string.split(m.source_app_ids, '','')) acap on acap.column_value = nvl(v(''APP_ID''), ''100'')',
'      connect by prior m.entry_id = m.parent_entry',
'      start with m.parent_entry is null',
'      order siblings by m.order_nr)',
'select muey.row_number',
'      ,muey.niveau                 as "LEVEL"',
'      ,case when regexp_instr(muey.entry_title, '''', 1, 1) > 0',
'          then abm_00000_menu_pck.subst_strings(in_string => muey.entry_title)',
'          else muey.entry_title',
'       end as "LABEL"',
'      ,muey.curr_app_id',
'      ,case',
'         when muey.target_url_type = ''STATIC''',
'           then abm_00000_menu_pck.subst_strings(muey.target_url)',
'         when muey.target_app_id is null or muey.target_page_id is null',
'           then ''#''',
'           else apex_page.get_url(p_application => muey.target_app_id',
'                                 ,p_page        => muey.target_page_id',
'                                 ,p_items       => muey.target_items',
'                                 ,p_values      => muey.target_values',
'                                 ,p_request     => muey.target_request)',
'       end as target',
'      ,case',
'         when muey.active_for_type = ''CHILDREN''',
'           and instr(muey.cbt, ''/'' || muey.curr_app_id || '':'' || muey.curr_page_id || '':'' || muey.entry_id) > 0',
'           then ''YES''',
'         when muey.active_for_type = ''SELF''',
'           and muey.cbt = ''/'' || muey.curr_app_id || '':'' || muey.curr_page_id || '':'' || muey.entry_id',
'           then ''YES''',
'         when muey.active_for_type = ''PLSQL''',
'           and abm_00000_menu_pck.validate_condition(in_condition => muey.active_for) = ''TRUE''',
'           then ''YES''',
'         when muey.active_for_type = ''NEVER'' then ''NO''',
'         else ''NO''',
'       end                         as is_current_list_entry',
'      ,muey.icon                   as image',
'      ,muey.image_attributes       as image_attribute',
'      ,muey.image_alt              as image_alt_attribute',
'      ,muey.attribute1',
'      ,muey.attribute2',
'      ,muey.attribute3',
'      ,muey.attribute4',
'      ,muey.attribute5',
'      ,muey.attribute6',
'      ,muey.attribute7',
'      ,muey.attribute8',
'      ,muey.attribute9',
'      ,muey.attribute10',
'  from iv_menu_entries muey',
'  where muey.ssc_result = ''TRUE''',
'  order by muey.row_number',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "ABM_ABM_01001_MENU_ENTRIES_VW" ("ENTRY_LEVEL", "ENTRY_ID", "PARENT_ENTRY", "ENTRY_TITLE", "SOURCE_APP_IDS", "ACTIVE_FOR", "ACTIVE_FOR_TYPE", "TARGET_APP_ID", "TARGET_PAGE_ID", "TARGET_URL", "TARGET_REQUEST", '
||'"ICON", "SERVER_SIDE_CONDITION", "ATTRIBUTE1", "ATTRIBUTE2", "ORDER_NR") AS ',
'  select level as entry_level',
'      ,muey.entry_id',
'      ,prnt.entry_title as parent_entry',
'      ,muey.entry_title',
'      ,muey.source_app_ids',
'      ,muey.active_for',
'      ,muey.active_for_type',
'      ,muey.target_app_id',
'      ,muey.target_page_id',
'      ,muey.target_url',
'      --,muey.target_url_type',
'      --,muey.target_items',
'      --,muey.target_values',
'      ,muey.target_request',
'      ,muey.icon',
'      --,muey.image',
'      --,muey.image_attributes',
'      --,muey.image_alt',
'      ,nvl2(muey.server_side_condition, ''Yes'', ''No'') as server_side_condition',
'      ,muey.attribute1',
'      ,muey.attribute2',
'      --,muey.attribute3',
'      --,muey.attribute4',
'      --,muey.attribute5',
'      --,muey.attribute6',
'      --,muey.attribute7',
'      --,muey.attribute8',
'      --,muey.attribute9',
'      --,muey.attribute10',
'      ,muey.order_nr',
'  from abm_menu_entries muey',
'    left join abm_menu_entries prnt on prnt.entry_id = muey.parent_entry',
'  connect by prior muey.entry_id = muey.parent_entry',
'  start with muey.parent_entry is null',
'  order siblings by muey.order_nr',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "ABM_ABM_01002_MENU_ENTRIES_VW" ("ENTRY_ID", "ENTRY_TITLE", "SOURCE_APP_IDS", "ACTIVE_FOR", "ACTIVE_FOR_TYPE", "TARGET_APP_ID", "TARGET_PAGE_ID", "TARGET_URL", "TARGET_URL_TYPE", "TARGET_ITEMS", "TARGET_VALUES'
||'", "TARGET_REQUEST", "ICON", "IMAGE", "IMAGE_ATTRIBUTES", "IMAGE_ALT", "SERVER_SIDE_CONDITION", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "PARENT_ENTRY'
||'", "ORDER_NR") AS ',
'  select muey.entry_id',
'      ,muey.entry_title',
'      ,muey.source_app_ids',
'      ,muey.active_for',
'      ,muey.active_for_type',
'      ,muey.target_app_id',
'      ,muey.target_page_id',
'      ,muey.target_url',
'      ,muey.target_url_type',
'      ,muey.target_items',
'      ,muey.target_values',
'      ,muey.target_request',
'      ,muey.icon',
'      ,muey.image',
'      ,muey.image_attributes',
'      ,muey.image_alt',
'      ,muey.server_side_condition',
'      ,muey.attribute1',
'      ,muey.attribute2',
'      ,muey.attribute3',
'      ,muey.attribute4',
'      ,muey.attribute5',
'      ,muey.attribute6',
'      ,muey.attribute7',
'      ,muey.attribute8',
'      ,muey.attribute9',
'      ,muey.attribute10',
'      ,muey.parent_entry',
'      ,muey.order_nr',
'  from abm_menu_entries muey',
';',
'',
'CREATE OR REPLACE FORCE EDITIONABLE VIEW "ABM_LOV_WORKSPACE_APPLICATIONS_VW" ("APPLICATION_GROUP", "APPLICATION_NAME", "APPLICATION_ID", "ALIAS", "DISPLAY_VALUE") AS ',
'  select axan.application_group',
'      ,axan.application_name',
'      ,axan.application_id',
'      ,axan.alias',
'      ,axan.application_name || '' ('' || axan.application_id || '')'' as display_value',
'  from apex_applications axan',
';',
'',
''))
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(24048403806718324)
,p_script_id=>wwv_flow_imp.id(24048381613718323)
,p_object_owner=>'#OWNER#'
,p_object_type=>'VIEW'
,p_object_name=>'ABM_00000_MENU_ENTRIES_VW'
,p_last_updated_by=>'RICHARD.MARTENS@GMAIL.COM'
,p_last_updated_on=>to_date('20230324151754','YYYYMMDDHH24MISS')
,p_created_by=>'RICHARD.MARTENS@GMAIL.COM'
,p_created_on=>to_date('20230324151754','YYYYMMDDHH24MISS')
);
